class Solution:
    def mergeArrays(self, nums1, nums2):
        totals = {}
        order = []
        for id_, v in nums1 + nums2:
            if id_ not in totals:
                order.append(id_)
                totals[id_] = 0
            totals[id_] += v
        return [[k, totals[k]] for k in sorted(order)]

