var mergeArrays = function(nums1, nums2) {
    let i = 0, j = 0;
    const res = [];
    while (i < nums1.length && j < nums2.length) {
        const [id1, v1] = nums1[i];
        const [id2, v2] = nums2[j];
        if (id1 === id2) {
            res.push([id1, v1 + v2]);
            i++; j++;
        } else if (id1 < id2) {
            res.push([id1, v1]);
            i++;
        } else {
            res.push([id2, v2]);
            j++;
        }
    }
    while (i < nums1.length) res.push(nums1[i++]);
    while (j < nums2.length) res.push(nums2[j++]);
    return res;
};
